mapper.select:
select

from article a
left join category c on c.id = a.category_id and c.status = 'visible'

    a.status = 'published'

        and (
            a.title like concat('%', #{keyword}, '%')
            or a.summary like concat('%', #{keyword}, '%')
        )


        and a.category_id = #{categoryId}


        and exists (
            select 1
            from article_tag at_filter
            where at_filter.article_id = a.id
            and at_filter.tag_id in

                #{tagId}

        )


        and extract(year from a.published_at) = #{year}


        and extract(month from a.published_at) = #{month}


order by

select count(1)
from article_like
where article_id = #{articleId}
and visitor_key_hash = #{visitorKeyHash}

select count(1)
from article_like
where ip_hash = #{ipHash}
and created_at >= #{since}

select min(created_at)
from article_like
where ip_hash = #{ipHash}
and created_at >= #{since}
